<?php
 namespace WPAICG\Includes\HookRegistrars; use WPAICG\Chat\Initializer as ChatInitializer; use WPAICG\AutoGPT\AIPKit_Automated_Task_Cron; use WPAICG\AIForms\AIPKit_AI_Form_Initializer; if (!defined('ABSPATH')) { exit; } class Module_Initializer_Hooks_Registrar { public static function register() { if (class_exists(ChatInitializer::class) && method_exists(ChatInitializer::class, 'register_hooks')) { ChatInitializer::register_hooks(); } if (self::should_boot_automated_tasks() && class_exists(AIPKit_Automated_Task_Cron::class) && method_exists(AIPKit_Automated_Task_Cron::class, 'init')) { AIPKit_Automated_Task_Cron::init(); } if (class_exists(AIPKit_AI_Form_Initializer::class) && method_exists(AIPKit_AI_Form_Initializer::class, 'register_hooks')) { AIPKit_AI_Form_Initializer::register_hooks(); } } private static function should_boot_automated_tasks(): bool { if (is_admin() || wp_doing_cron()) { return true; } return defined('WP_CLI') && WP_CLI; } } 